import{_ as t,o as a,c as n,a2 as d}from"./chunks/framework.DeNJmwJc.js";const g=JSON.parse('{"title":"Chapter 17 — Change Commands","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/17-change-commands.md","filePath":"chapters/17-change-commands.md"}'),s={name:"chapters/17-change-commands.md"};function o(c,e,i,r,l,h){return a(),n("div",null,[...e[0]||(e[0]=[d(`<h1 id="chapter-17-—-change-commands" tabindex="-1">Chapter 17 — Change Commands <a class="header-anchor" href="#chapter-17-—-change-commands" aria-label="Permalink to &quot;Chapter 17 — Change Commands&quot;">​</a></h1><blockquote><p><em>&quot;Change is delete with purpose—remove old text and replace it with new in one command.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 15–20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>The <strong>change</strong> command (<code>c</code>) is like delete, but it automatically enters insert mode afterward.</p><p>This makes it ideal for replacing text.</p><hr><h1 id="the-change-operator" tabindex="-1">The Change Operator <a class="header-anchor" href="#the-change-operator" aria-label="Permalink to &quot;The Change Operator&quot;">​</a></h1><p><code>c</code> is an operator. It works like <code>d</code>, but:</p><ol><li>Deletes the specified text.</li><li>Enters insert mode immediately.</li></ol><hr><h1 id="change-by-motion" tabindex="-1">Change by Motion <a class="header-anchor" href="#change-by-motion" aria-label="Permalink to &quot;Change by Motion&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>cw</code></td><td>Change to end of word (and insert)</td></tr><tr><td><code>cW</code></td><td>Change to end of WORD</td></tr><tr><td><code>cb</code></td><td>Change backward to beginning of word</td></tr><tr><td><code>c$</code></td><td>Change to end of line</td></tr><tr><td><code>c0</code></td><td>Change to beginning of line</td></tr><tr><td><code>c^</code></td><td>Change to first non-blank character</td></tr><tr><td><code>cG</code></td><td>Change to end of file</td></tr><tr><td><code>cgg</code></td><td>Change to beginning of file</td></tr><tr><td><code>c%</code></td><td>Change to matching bracket</td></tr><tr><td><code>c/foo</code></td><td>Change to next occurrence of &quot;foo&quot;</td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function add(a, b) {</span></span>
<span class="line"><span>         ^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press cw, type &quot;subtract&quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>function subtract(a, b) {</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>print(&quot;Hello World&quot;);</span></span>
<span class="line"><span>            ^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press c$, type &quot;Goodbye!&quot;);:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>print(&quot;Goodbye!&quot;);</span></span></code></pre></div><hr><h1 id="change-line" tabindex="-1">Change Line <a class="header-anchor" href="#change-line" aria-label="Permalink to &quot;Change Line&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>cc</code></td><td>Change entire line (delete line + insert)</td></tr><tr><td><code>C</code></td><td>Change to end of line (same as c$)</td></tr><tr><td><code>S</code></td><td>Change entire line (same as cc)</td></tr></tbody></table><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>line 1</span></span>
<span class="line"><span>line 2   ← cursor here</span></span>
<span class="line"><span>line 3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press cc:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>line 1</span></span>
<span class="line"><span>         ← blank, insert mode active</span></span>
<span class="line"><span>line 3</span></span></code></pre></div><hr><h1 id="change-with-text-objects" tabindex="-1">Change with Text Objects <a class="header-anchor" href="#change-with-text-objects" aria-label="Permalink to &quot;Change with Text Objects&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>ciw</code></td><td>Change inner word</td></tr><tr><td><code>caw</code></td><td>Change a word (including trailing space)</td></tr><tr><td><code>ci(</code></td><td>Change inside parentheses</td></tr><tr><td><code>ci&quot;</code></td><td>Change inside double quotes</td></tr><tr><td><code>ci&#39;</code></td><td>Change inside single quotes</td></tr><tr><td><code>ci[</code></td><td>Change inside square brackets</td></tr><tr><td><code>ci{</code></td><td>Change inside curly braces</td></tr><tr><td><code>cit</code></td><td>Change inside HTML tag</td></tr></tbody></table><p>Text objects make change extremely powerful.</p><hr><h1 id="change-vs-delete" tabindex="-1">Change vs Delete <a class="header-anchor" href="#change-vs-delete" aria-label="Permalink to &quot;Change vs Delete&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Action</th><th>After the Command</th></tr></thead><tbody><tr><td><code>dw</code></td><td>Still in normal mode</td></tr><tr><td><code>cw</code></td><td>Enters insert mode</td></tr></tbody></table><p>Use <code>d</code> when you want to remove text.</p><p>Use <code>c</code> when you want to remove and replace text.</p><hr><h1 id="change-with-counts" tabindex="-1">Change with Counts <a class="header-anchor" href="#change-with-counts" aria-label="Permalink to &quot;Change with Counts&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>c3w</code></td><td>Change next 3 words</td></tr><tr><td><code>c2$</code></td><td>Change to end of 2 lines</td></tr><tr><td><code>c5j</code></td><td>Change 5 lines down</td></tr></tbody></table><hr><h1 id="change-inside-quotes-example" tabindex="-1">Change Inside Quotes Example <a class="header-anchor" href="#change-inside-quotes-example" aria-label="Permalink to &quot;Change Inside Quotes Example&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>message = &quot;Hello World&quot;;</span></span>
<span class="line"><span>           ^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press ci&quot; :</span></span>
<span class="line"><span></span></span>
<span class="line"><span>message = &quot;&quot;;</span></span>
<span class="line"><span>                ^ cursor here, insert mode active</span></span>
<span class="line"><span>Type &quot;Goodbye&quot; :</span></span>
<span class="line"><span></span></span>
<span class="line"><span>message = &quot;Goodbye&quot;;</span></span></code></pre></div><p>This is one of the most frequently used Vim commands.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>cw</code></td><td>Change word</td></tr><tr><td><code>cc</code></td><td>Change line</td></tr><tr><td><code>C</code></td><td>Change to end of line</td></tr><tr><td><code>ciw</code></td><td>Change inner word</td></tr><tr><td><code>ci(</code></td><td>Change inside parentheses</td></tr><tr><td><code>ci&quot;</code></td><td>Change inside quotes</td></tr><tr><td><code>c$</code></td><td>Change to end of line</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>c</code> = delete + insert mode in one command.</li><li><code>cc</code> changes the whole line.</li><li><code>C</code> changes from cursor to end of line.</li><li><code>ci&quot;</code>, <code>ci(</code>, <code>ci{</code> are extremely useful for code.</li><li>Use <code>d</code> to remove, <code>c</code> to replace.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and change a word with <code>cw</code>.</li><li>Change a line with <code>cc</code>.</li><li>Change inside parentheses with <code>ci(</code>.</li><li>Change inside quotes with <code>ci&quot;</code>.</li><li>Compare <code>dw</code> (delete) vs <code>cw</code> (change).</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./18-copy-paste.html"><strong>Chapter 18 — Copy &amp; Paste</strong></a></p><p>Master yanking (copying) and putting (pasting) in Vim.</p>`,52)])])}const m=t(s,[["render",o]]);export{g as __pageData,m as default};
